window.BJT_CHOUDOKKAI = [

  {"id":"c101","sec":"状況をつかむ","material":"<div class=\"mtl-scene\"><svg width=\"210\" height=\"98\" viewBox=\"0 0 210 98\" xmlns=\"http://www.w3.org/2000/svg\"><rect x=\"25\" y=\"58\" width=\"160\" height=\"26\" rx=\"4\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><circle cx=\"70\" cy=\"42\" r=\"13\" fill=\"#3C5A78\"/><rect x=\"58\" y=\"54\" width=\"24\" height=\"8\" rx=\"4\" fill=\"#3C5A78\"/><circle cx=\"140\" cy=\"42\" r=\"13\" fill=\"#9CB2C8\"/><rect x=\"128\" y=\"54\" width=\"24\" height=\"8\" rx=\"4\" fill=\"#9CB2C8\"/><circle cx=\"105\" cy=\"70\" r=\"5\" fill=\"#fff\" stroke=\"#3C5A78\"/></svg><div class=\"mtl-cap\">会社の 受付</div></div>","setup":"会社の 受付で、男の人と 受付の 人が 話して います。","turns":[{"w":"男","t":"営業部の 田中さんと 二時に お約束の 者ですが。"},{"w":"女","t":"山川 商事の 佐藤様で いらっしゃいますね。ただいま 田中を 呼んで まいります。少々 お待ちください。"}],"q":"男の人は、だれに 会いに 来ましたか。","cs":["営業部の 田中さん","山川商事の 佐藤さん（来客 本人）","受付の 担当者","経理部の 田中さん"],"a":0,"ex":"来客は「営業部の田中さんと約束」と言っています。佐藤は来客自身の名前で、受付の人・別部署の田中ではありません。"},

  {"id":"c102","sec":"状況をつかむ","material":"<div class=\"mtl-scene\"><svg width=\"210\" height=\"98\" viewBox=\"0 0 210 98\" xmlns=\"http://www.w3.org/2000/svg\"><circle cx=\"105\" cy=\"34\" r=\"15\" fill=\"#3C5A78\"/><rect x=\"90\" y=\"47\" width=\"30\" height=\"10\" rx=\"5\" fill=\"#3C5A78\"/><path d=\"M60 70 q-6 -14 8 -20 l6 10 q-8 4 -2 12 z\" fill=\"#4A6B8A\"/><path d=\"M150 70 q6 -14 -8 -20 l-6 10 q8 4 2 12 z\" fill=\"#4A6B8A\"/></svg><div class=\"mtl-cap\">オフィスで 電話</div></div>","setup":"会社で、女の人が 電話で 話して います。","turns":[{"w":"女","t":"はい、承知いたしました。……はい、来週 火曜の お打ち合わせですね。場所を、御社から 弊社に 変更、と。かしこまりました。では、当日 お待ちして おります。"}],"q":"電話の 用件は 何でしたか。","cs":["打ち合わせの 場所の 変更","打ち合わせの 日時の 変更","打ち合わせの 中止","参加者の 変更"],"a":0,"ex":"「場所を御社から弊社に変更」と話しています。日時・中止・参加者の変更ではありません。"},

  {"id":"c103","sec":"状況をつかむ","material":"<div class=\"mtl-scene\"><svg width=\"210\" height=\"98\" viewBox=\"0 0 210 98\" xmlns=\"http://www.w3.org/2000/svg\"><rect x=\"60\" y=\"24\" width=\"40\" height=\"60\" rx=\"2\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><line x1=\"80\" y1=\"24\" x2=\"80\" y2=\"84\" stroke=\"#3C5A78\"/><rect x=\"110\" y=\"24\" width=\"40\" height=\"60\" rx=\"2\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><line x1=\"130\" y1=\"24\" x2=\"130\" y2=\"84\" stroke=\"#3C5A78\"/><path d=\"M40 44 l8 -10 l8 10 z\" fill=\"#3C5A78\"/><path d=\"M40 60 l8 10 l8 -10 z\" fill=\"#9CB2C8\"/></svg><div class=\"mtl-cap\">エレベーターの 前</div></div>","setup":"会社の エレベーターの 前で、二人の 社員が 話して います。","turns":[{"w":"男","t":"お昼、どう する？"},{"w":"女","t":"上の 階の 社員食堂、今日から 新しい メニューが 始まった みたいですよ。"},{"w":"男","t":"へえ、じゃあ そこに 行って みよう。"}],"q":"二人は これから どこへ 行きますか。","cs":["上の 階の 社員食堂","駅前の レストラン","会社の 近くの 店","地下の 売店"],"a":0,"ex":"「上の階の社員食堂に行ってみよう」と決めています。外のレストラン・近くの店・地下の売店ではありません。"},

  {"id":"c104","sec":"状況をつかむ","material":"<div class=\"mtl-scene\"><svg width=\"210\" height=\"98\" viewBox=\"0 0 210 98\" xmlns=\"http://www.w3.org/2000/svg\"><ellipse cx=\"105\" cy=\"60\" rx=\"70\" ry=\"22\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><circle cx=\"55\" cy=\"44\" r=\"10\" fill=\"#3C5A78\"/><circle cx=\"105\" cy=\"38\" r=\"10\" fill=\"#9CB2C8\"/><circle cx=\"155\" cy=\"44\" r=\"10\" fill=\"#3C5A78\"/><circle cx=\"80\" cy=\"78\" r=\"10\" fill=\"#9CB2C8\"/><circle cx=\"130\" cy=\"78\" r=\"10\" fill=\"#3C5A78\"/></svg><div class=\"mtl-cap\">会議室</div></div>","setup":"会議室で、会議が 終わろうと して います。","turns":[{"w":"男","t":"それでは、本日は ここまでと します。次回は 来週の 金曜、午後 三時から、この 部屋で 行います。"},{"w":"女","t":"来週 金曜 三時ですね。承知しました。"}],"q":"次の 会議は いつ ありますか。","cs":["来週の 金曜 午後三時","今週の 金曜 午後三時","来週の 月曜 午後三時","来週の 金曜 午後一時"],"a":0,"ex":"「次回は来週の金曜、午後三時から」と言い、相手も確認しています。今週・月曜・一時ではありません。"},

  {"id":"c105","sec":"状況をつかむ","material":"<div class=\"mtl-scene\"><svg width=\"210\" height=\"98\" viewBox=\"0 0 210 98\" xmlns=\"http://www.w3.org/2000/svg\"><rect x=\"30\" y=\"60\" width=\"150\" height=\"26\" rx=\"3\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><rect x=\"120\" y=\"40\" width=\"46\" height=\"24\" rx=\"3\" fill=\"#4A6B8A\"/><rect x=\"128\" y=\"46\" width=\"30\" height=\"8\" fill=\"#fff\"/><circle cx=\"70\" cy=\"40\" r=\"13\" fill=\"#9CB2C8\"/><rect x=\"58\" y=\"52\" width=\"24\" height=\"10\" rx=\"5\" fill=\"#9CB2C8\"/></svg><div class=\"mtl-cap\">店の レジ</div></div>","setup":"店の レジで、店員と 客が 話して います。","turns":[{"w":"女","t":"お会計は 全部で 三千二百円で ございます。お支払いは いかが なさいますか。"},{"w":"男","t":"カードで お願いします。"},{"w":"女","t":"かしこまりました。カードを お預かりいたします。"}],"q":"客は どうやって 支払いますか。","cs":["カード","現金","商品券","電子マネー"],"a":0,"ex":"客は「カードでお願いします」と言っています。現金・商品券・電子マネーではありません。"},

  {"id":"c201","sec":"資料を見て聞く","material":"<table class=\"mtl-t\"><tr><th>時間</th><th>会議</th><th>場所</th></tr><tr><td>10:00</td><td class=\"l\">企画会議</td><td>第1会議室</td></tr><tr><td>13:00</td><td class=\"l\">営業会議</td><td>第3会議室</td></tr><tr><td>15:30</td><td class=\"l\">部内 打ち合わせ</td><td>第2会議室</td></tr></table>","setup":"会社で、女の人が 今日の 予定表を 見ながら 話して います。","turns":[{"w":"女","t":"ええと、午後 いちばん 早い 会議に 出ないと。資料は そろって いるかな。"}],"q":"女の人が 出る 会議は、どこで 行われますか。","cs":["第3会議室","第1会議室","第2会議室","応接室"],"a":0,"ex":"午後いちばん早い会議＝13:00の営業会議で、表より場所は第3会議室。第1は午前、第2は15:30、応接室は表にありません。"},

  {"id":"c202","sec":"資料を見て聞く","material":"<table class=\"mtl-t\"><tr><th>プラン</th><th>月額</th><th>データ量</th></tr><tr><td>ライト</td><td>1,000円</td><td>3GB</td></tr><tr><td>スタンダード</td><td>2,500円</td><td>20GB</td></tr><tr><td>プレミアム</td><td>4,000円</td><td>無制限</td></tr></table>","setup":"携帯電話の 店で、男の人が プランを 選んで います。","turns":[{"w":"男","t":"毎月 動画を たくさん 見るので、データ量を 気にせず 使える プランに したいです。"}],"q":"男の人が 選ぶ プランの 月額は いくらですか。","cs":["4,000円","2,500円","1,000円","3,000円"],"a":0,"ex":"データ量を気にせず＝無制限の「プレミアム」で月額4,000円。2,500はスタンダード、1,000はライト、3,000は表にありません。"},

  {"id":"c203","sec":"資料を見て聞く","material":"<table class=\"mtl-t\"><tr><th>階</th><th>部署</th></tr><tr><td>4階</td><td class=\"l\">役員室・応接室</td></tr><tr><td>3階</td><td class=\"l\">経理部・総務部</td></tr><tr><td>2階</td><td class=\"l\">営業部</td></tr><tr><td>1階</td><td class=\"l\">受付・会議室</td></tr></table>","setup":"会社で、先輩が 新入社員に 用事を 頼んで います。","turns":[{"w":"男","t":"この 書類、経理部に 届けて きて もらえる？"}],"q":"新入社員は 何階へ 行けば よいですか。","cs":["3階","2階","1階","4階"],"a":0,"ex":"経理部は案内図より3階。2階は営業部、1階は受付・会議室、4階は役員室・応接室です。"},

  {"id":"c204","sec":"資料を見て聞く","material":"<table class=\"mtl-t\"><tr><th>発車</th><th>種類</th><th>行き先</th></tr><tr><td>9:50</td><td>普通</td><td>本社前</td></tr><tr><td>10:10</td><td class=\"l\"><span class=\"mtl-hl\">特急</span></td><td>本社前</td></tr><tr><td>10:25</td><td>普通</td><td>本社前</td></tr><tr><td>10:40</td><td>特急</td><td>本社前</td></tr></table>","setup":"駅で、男の人が 時刻表を 見ながら 話して います。","turns":[{"w":"男","t":"急いで いるから、10時 すぎに 出る いちばん 早い 特急に 乗ろう。"}],"q":"男の人が 乗る 電車は 何時 発ですか。","cs":["10:10","9:50","10:25","10:40"],"a":0,"ex":"10時すぎで最初の特急は10:10。9:50は10時前、10:25は普通、10:40は次の特急です。"},

  {"id":"c205","sec":"資料を見て聞く","material":"<div class=\"mtl-mail\">件名：新人 研修の ご案内\n\n新入社員の みなさま\n\n来週 月曜、9時から 研修を 行います。\n場所：3階 大会議室\n持ち物：<span class=\"mtl-hl\">筆記用具</span>（昼食は こちらで 用意します）\n　　　　　　　　　　　　総務部</div>","setup":"新入社員の 男の人が、研修の 案内メールを 見ながら 同僚に 聞いて います。","turns":[{"w":"男","t":"この 研修、何か 持って いく 物 って あった かな。"}],"q":"研修に 何を 持って いきますか。","cs":["筆記用具","昼食","パソコン","印鑑"],"a":0,"ex":"メールに「持ち物：筆記用具」とあります。昼食は用意され、パソコン・印鑑は書かれていません。"},

  {"id":"c206","sec":"資料を見て聞く","material":"<table class=\"mtl-t\"><tr><th>品名</th><th>数量</th></tr><tr><td class=\"l\">コピー用紙</td><td>5</td></tr><tr><td class=\"l\">ボールペン</td><td>12</td></tr><tr><td class=\"l\">封筒</td><td>3</td></tr></table>","setup":"会社で、女の人が 注文書を 見ながら 話して います。","turns":[{"w":"女","t":"いちばん たくさん 注文する 物を、間違えない ように しないと ね。"}],"q":"いちばん 数量が 多い 品物は 何ですか。","cs":["ボールペン","コピー用紙","封筒","のり"],"a":0,"ex":"注文書の数量はボールペンが12でいちばん多いです。コピー用紙5・封筒3・のり（表になし）ではありません。"},

  {"id":"c207","sec":"資料を見て聞く","material":"<table class=\"mtl-t\"><tr><th>部屋</th><th>定員</th><th>14時</th></tr><tr><td class=\"l\">A室</td><td>4名</td><td>×</td></tr><tr><td class=\"l\">B室</td><td>8名</td><td>○</td></tr><tr><td class=\"l\">C室</td><td>12名</td><td>×</td></tr></table><div style=\"font-size:11px;color:#6B6560;margin-top:4px\">○=空き ×=予約済み</div>","setup":"会社で、男の人が 会議室の 予約表を 見て います。","turns":[{"w":"男","t":"14時に、6人 入れる 部屋を 取りたいんだ。空いて いる 所は あるかな。"}],"q":"14時に 予約できる 部屋は どれですか。","cs":["B室","A室","C室","どれも 空いていない"],"a":0,"ex":"6人入り（定員8名）で14時が○のB室が正解。A室は定員不足、C室は予約済みです。"},

  {"id":"c208","sec":"資料を見て聞く","material":"<svg width=\"210\" height=\"110\" viewBox=\"0 0 210 110\" xmlns=\"http://www.w3.org/2000/svg\"><line x1=\"0\" y1=\"60\" x2=\"210\" y2=\"60\" stroke=\"#bbb\" stroke-width=\"8\"/><rect x=\"20\" y=\"20\" width=\"46\" height=\"28\" rx=\"3\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><text x=\"43\" y=\"38\" font-size=\"11\" text-anchor=\"middle\" fill=\"#3C5A78\">銀行</text><rect x=\"150\" y=\"20\" width=\"46\" height=\"28\" rx=\"3\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><text x=\"173\" y=\"38\" font-size=\"11\" text-anchor=\"middle\" fill=\"#3C5A78\">郵便局</text><rect x=\"86\" y=\"72\" width=\"46\" height=\"28\" rx=\"3\" fill=\"#FAEEDA\" stroke=\"#854F0B\"/><text x=\"109\" y=\"90\" font-size=\"11\" text-anchor=\"middle\" fill=\"#854F0B\">駅</text><text x=\"105\" y=\"14\" font-size=\"10\" text-anchor=\"middle\" fill=\"#6B6560\">← 大通り →</text></svg>","setup":"駅の 前で、女の人が 地図を 見ながら 話して います。","turns":[{"w":"女","t":"駅を 出て 大通りを わたって、左の ほうに 行けば いいのね。"}],"q":"女の人が 行こうと して いるのは どこですか。","cs":["銀行","郵便局","会社","コンビニ"],"a":0,"ex":"大通りの向こう、左が銀行、右が郵便局。左に行くので銀行です。会社・コンビニは図にありません。"},

  {"id":"c209","sec":"資料を見て聞く","material":"<table class=\"mtl-t\"><tr><th>商品</th><th>重さ</th><th>特徴</th></tr><tr><td>A</td><td>1.8kg</td><td class=\"l\">画面が 大きい</td></tr><tr><td>B</td><td>0.9kg</td><td class=\"l\">軽い・持ち運び 便利</td></tr><tr><td>C</td><td>1.4kg</td><td class=\"l\">電池が 長もち</td></tr></table>","setup":"店で、女の人が カタログを 見ながら 話して います。","turns":[{"w":"女","t":"毎日 かばんに 入れて 持ち歩くので、とにかく 軽い のが いいな。"}],"q":"女の人に 合う 商品は どれですか。","cs":["商品B","商品A","商品C","どれも 合わない"],"a":0,"ex":"「軽いのがいい」＝最も軽い（0.9kg・持ち運び便利）の商品B。A（画面が大きい）・C（電池が長もち）ではありません。"},

  {"id":"c210","sec":"資料を見て聞く","material":"<div class=\"mtl-notice\"><div class=\"nt-t\">ゴミ 分別の お願い</div>燃える ゴミ：月・木<br>びん・かん：<span class=\"mtl-hl\">水</span><br>ペットボトル：金</div>","setup":"会社で、男の人が 掲示を 見ながら 同僚に 聞いて います。","turns":[{"w":"男","t":"この 空き かん、何曜日に 出せば いいのかな。"}],"q":"びん・かんは 何曜日に 出しますか。","cs":["水曜日","月曜日","木曜日","金曜日"],"a":0,"ex":"掲示に「びん・かん：水」とあります。月・木は燃えるゴミ、金はペットボトルです。"},

  {"id":"c301","sec":"総合的に聞く","material":"<table class=\"mtl-t\"><tr><th>時間</th><th>予定</th></tr><tr><td>10:00</td><td class=\"l\">A社 訪問</td></tr><tr><td>13:00</td><td class=\"l\">社内 会議</td></tr><tr><td>15:00</td><td class=\"l\">資料 作成</td></tr></table>","setup":"会社で、男の人と 女の人が 今日の 予定を 見ながら 話して います。","turns":[{"w":"男","t":"この あとの 社内会議だけど、部長の 都合で 一時間 遅く なったよ。"},{"w":"女","t":"じゃあ、14時 からですね。予定表、直して おきます。"}],"q":"社内会議は 何時から に なりましたか。","cs":["14時","13時","15時","10時"],"a":0,"ex":"資料では13時ですが、一時間遅れて14時。女の人も確認しています。13時は元の時間、15時は資料作成、10時はA社訪問です。"},

  {"id":"c302","sec":"総合的に聞く","material":"<svg width=\"230\" height=\"130\" viewBox=\"0 0 230 130\" xmlns=\"http://www.w3.org/2000/svg\"><line x1=\"28\" y1=\"104\" x2=\"220\" y2=\"104\" stroke=\"#ccc\"/><rect x=\"40\" y=\"72\" width=\"30\" height=\"32\" fill=\"#9CB2C8\"/><text x=\"55\" y=\"118\" font-size=\"10\" text-anchor=\"middle\" fill=\"#6B6560\">1期</text><text x=\"55\" y=\"66\" font-size=\"9\" text-anchor=\"middle\" fill=\"#6B6560\">40</text><rect x=\"90\" y=\"56\" width=\"30\" height=\"48\" fill=\"#9CB2C8\"/><text x=\"105\" y=\"118\" font-size=\"10\" text-anchor=\"middle\" fill=\"#6B6560\">2期</text><text x=\"105\" y=\"50\" font-size=\"9\" text-anchor=\"middle\" fill=\"#6B6560\">55</text><rect x=\"140\" y=\"64\" width=\"30\" height=\"40\" fill=\"#9CB2C8\"/><text x=\"155\" y=\"118\" font-size=\"10\" text-anchor=\"middle\" fill=\"#6B6560\">3期</text><text x=\"155\" y=\"58\" font-size=\"9\" text-anchor=\"middle\" fill=\"#6B6560\">50</text><rect x=\"190\" y=\"30\" width=\"30\" height=\"74\" fill=\"#3C5A78\"/><text x=\"205\" y=\"118\" font-size=\"10\" text-anchor=\"middle\" fill=\"#6B6560\">4期</text><text x=\"205\" y=\"24\" font-size=\"9\" text-anchor=\"middle\" fill=\"#3C5A78\">80</text><text x=\"20\" y=\"20\" font-size=\"10\" fill=\"#6B6560\">(万円)</text></svg>","setup":"会議で、男の人が グラフを 見せながら 説明して います。","turns":[{"w":"男","t":"こちらは 昨年の 売上の グラフです。前半は あまり 変わりませんでしたが、後半、特に 最後の 期に 大きく 伸びました。"}],"q":"売上が いちばん 高かったのは どの 期ですか。","cs":["4期","2期","3期","1期"],"a":0,"ex":"「最後の期に大きく伸びた」との説明どおり、グラフでも4期が80万円で最高。2期55・3期50・1期40です。"},

  {"id":"c303","sec":"総合的に聞く","material":"<table class=\"mtl-t\"><tr><th>セット</th><th>内容</th><th>値段</th></tr><tr><td>A</td><td class=\"l\">コーヒー＋パン</td><td>500円</td></tr><tr><td>B</td><td class=\"l\">紅茶＋ケーキ</td><td>700円</td></tr><tr><td>C</td><td class=\"l\">ジュース＋サンド</td><td>800円</td></tr></table>","setup":"喫茶店で、女の人と 男の人が メニューを 見て 話して います。","turns":[{"w":"女","t":"私、甘い ものが 食べたいな。ケーキの セットに しようかな。"},{"w":"男","t":"じゃあ 僕は、軽く パンで いいや。いちばん 安いのに する。"}],"q":"男の人は どの セットを 注文しますか。","cs":["Aセット","Bセット","Cセット","注文しない"],"a":0,"ex":"男の人は「パンで、いちばん安いの」＝A（コーヒー＋パン・500円）。Bは女の人の分、Cは最も高いセットです。"},

  {"id":"c304","sec":"総合的に聞く","material":"<div class=\"mtl-mail\">件名：見積書 送付の 件\n\nお見積り金額：<span class=\"mtl-hl\">100,000円</span>\n納期：ご注文から 2週間\n※数量に よっては お値引き 可能です</div>","setup":"会社で、女の人が 見積書の メールを 見せながら、上司に 相談して います。","turns":[{"w":"女","t":"部長、A社への お見積りは 10万円ですが、よろしいでしょうか。"},{"w":"男","t":"うん。今回は 数量が 多いから、一割 引いて 出して おいて。"},{"w":"女","t":"かしこまりました。では 9万円で お送りします。"}],"q":"A社へ 出す 最終的な 金額は いくらですか。","cs":["90,000円","100,000円","80,000円","110,000円"],"a":0,"ex":"見積10万円を一割引きで9万円。10万円は割引前、8万・11万は誤りです。"},

  {"id":"c305","sec":"総合的に聞く","material":"<table class=\"mtl-t\"><tr><th>日</th><th>午前</th><th>午後</th></tr><tr><td>1日目</td><td class=\"l\">移動</td><td class=\"l\">支店で 会議</td></tr><tr><td>2日目</td><td class=\"l\">工場 見学</td><td class=\"l\">帰社</td></tr></table>","setup":"会社で、男の人と 女の人が 出張の 予定表を 見て 話して います。","turns":[{"w":"女","t":"2日目の 午前は 工場 見学の 予定でしたね。"},{"w":"男","t":"あ、それなんだけど、先方の 都合で 見学は 取りやめに なって、代わりに 支店で もう一度 会議を する ことに なったよ。"}],"q":"2日目の 午前は、何を する ことに なりましたか。","cs":["支店で 会議","工場 見学","移動","帰社"],"a":0,"ex":"予定表では工場見学ですが、会話で「見学は取りやめ、支店で会議」に変更。移動・帰社は別の時間帯です。"},

  {"id":"c306","sec":"総合的に聞く","material":"<div class=\"mtl-mail\">アンケート ご協力の お願い\n\n・所要時間：約5分\n・回答方法：下の QRコード\n・締切：<span class=\"mtl-hl\">今週 金曜</span></div>","setup":"会社で、男の人が アンケートの 用紙を 見せながら 話して います。","turns":[{"w":"男","t":"この お客様 アンケート、締切は 今週の 金曜ですが、回答が まだ 少ないんです。"},{"w":"女","t":"じゃあ、明日の 朝礼で もう一度 お願いを しましょう。"}],"q":"アンケートの 締切は いつですか。","cs":["今週の 金曜","今週の 水曜","来週の 金曜","明日"],"a":0,"ex":"用紙に「締切：今週金曜」とあり、男の人もそう言っています。水曜・来週・明日ではありません。"},

  {"id":"c307","sec":"総合的に聞く","material":"<table class=\"mtl-t\"><tr><th>重視する 点</th><th>割合</th></tr><tr><td class=\"l\">価格</td><td>40%</td></tr><tr><td class=\"l\">品質</td><td>35%</td></tr><tr><td class=\"l\">デザイン</td><td>15%</td></tr><tr><td class=\"l\">その他</td><td>10%</td></tr></table>","setup":"会議で、女の人が アンケートの 結果を 見せながら 説明して います。","turns":[{"w":"女","t":"お客様が 商品を 選ぶ とき、いちばん 多くの 方が 重視すると 答えた 点を 中心に、改善を 進めて まいります。"}],"q":"お客様が いちばん 重視して いるのは 何ですか。","cs":["価格","品質","デザイン","その他"],"a":0,"ex":"「いちばん多くの方が重視」＝表で最も割合が高い「価格（40%）」。品質35%・デザイン15%・その他10%です。"},

  {"id":"c308","sec":"総合的に聞く","material":"<svg width=\"210\" height=\"96\" viewBox=\"0 0 210 96\" xmlns=\"http://www.w3.org/2000/svg\"><rect x=\"70\" y=\"10\" width=\"70\" height=\"18\" rx=\"3\" fill=\"#FAEEDA\" stroke=\"#854F0B\"/><text x=\"105\" y=\"23\" font-size=\"10\" text-anchor=\"middle\" fill=\"#854F0B\">受付</text><rect x=\"30\" y=\"50\" width=\"44\" height=\"30\" rx=\"3\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><text x=\"52\" y=\"69\" font-size=\"11\" text-anchor=\"middle\" fill=\"#3C5A78\">1番</text><rect x=\"83\" y=\"50\" width=\"44\" height=\"30\" rx=\"3\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><text x=\"105\" y=\"69\" font-size=\"11\" text-anchor=\"middle\" fill=\"#3C5A78\">2番</text><rect x=\"136\" y=\"50\" width=\"44\" height=\"30\" rx=\"3\" fill=\"#E4EAF1\" stroke=\"#3C5A78\"/><text x=\"158\" y=\"69\" font-size=\"11\" text-anchor=\"middle\" fill=\"#3C5A78\">3番</text></svg>","setup":"展示会の 会場で、係の 人が ブースの 場所を 説明して います。","turns":[{"w":"女","t":"私たちの 会社の ブースは、受付から 見て いちばん 右の 場所です。"},{"w":"男","t":"右の はし、ですね。分かりました。"}],"q":"この 会社の ブースは 何番ですか。","cs":["3番","1番","2番","受付の 隣"],"a":0,"ex":"「受付から見ていちばん右」＝図の右端の3番。1番は左端、2番は中央です。"},

  {"id":"c309","sec":"総合的に聞く","material":"<table class=\"mtl-t\"><tr><th></th><th>価格</th><th>保証</th></tr><tr><td>P社</td><td>安い</td><td>1年</td></tr><tr><td>Q社</td><td>普通</td><td class=\"l\">3年</td></tr></table>","setup":"会社で、二人が 二つの 会社の 比較表を 見て 話して います。","turns":[{"w":"男","t":"P社は 安いけど、保証が 1年 だけ なんだよね。"},{"w":"女","t":"うちは 長く 使うから、少し 高くても 保証が 長い ほうが 安心ですよ。"},{"w":"男","t":"そうだね。じゃあ そっちに しよう。"}],"q":"二人は どちらの 会社に 決めましたか。","cs":["Q社","P社","どちらも やめる","まだ 決めない"],"a":0,"ex":"「保証が長いほうが安心」で合意。比較表で保証3年はQ社。P社は保証1年です。"},

  {"id":"c310","sec":"総合的に聞く","material":"<table class=\"mtl-t\"><tr><th>工程</th><th>締切</th></tr><tr><td class=\"l\">下書き</td><td>火曜</td></tr><tr><td class=\"l\">見直し</td><td>木曜</td></tr><tr><td class=\"l\">提出</td><td>金曜</td></tr></table>","setup":"会社で、上司と 部下が 作業の 予定表を 見て 話して います。","turns":[{"w":"男","t":"提出は 金曜だけど、会議が 一日 早まって 木曜に なったんだ。"},{"w":"女","t":"では、木曜の 会議までに 出せる よう、見直しを 一日 早めて 水曜に します。"}],"q":"見直しは、いつまでに 終わらせますか。","cs":["水曜","木曜","金曜","火曜"],"a":0,"ex":"会議が木曜に早まったため、見直しを予定表の木曜から一日早めて水曜。金曜は提出、火曜は下書きです。"},

  {"id":"c106","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><rect x='25' y='58' width='160' height='24' rx='4' fill='#E4EAF1' stroke='#3C5A78'/><circle cx='70' cy='40' r='13' fill='#3C5A78'/><rect x='58' y='52' width='24' height='8' rx='4' fill='#3C5A78'/><circle cx='140' cy='40' r='13' fill='#9CB2C8'/><rect x='128' y='52' width='24' height='8' rx='4' fill='#9CB2C8'/></svg><div class='mtl-cap'>会社の 受付</div></div>","setup":"会社の 受付で、来客と 受付の 人が 話して います。","turns":[{"w":"男","t":"山川 商事の 田中と 申します。企画部の 鈴木様と、三時に お約束を いただいて おります。"},{"w":"女","t":"田中様で いらっしゃいますね。ただいま 鈴木を 呼んで まいります。"}],"q":"来客は、だれに 会いに 来ましたか。","cs":["企画部の 鈴木さん","山川 商事の 田中さん","受付の 人","企画部の 山川さん"],"a":0,"ex":"来客は「企画部の鈴木様とお約束」と言っています。田中は来客自身の名前、山川は会社名です。名前と会社名を聞き分けます。"},

  {"id":"c107","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='200' height='90' viewBox='0 0 200 90' xmlns='http://www.w3.org/2000/svg'><circle cx='100' cy='34' r='15' fill='#3C5A78'/><rect x='85' y='47' width='30' height='10' rx='5' fill='#3C5A78'/><path d='M60 68 q-6 -13 7 -18 l5 9 q-7 3 -1 11 z' fill='#4A6B8A'/><path d='M140 68 q6 -13 -7 -18 l-5 9 q7 3 1 11 z' fill='#4A6B8A'/></svg><div class='mtl-cap'>オフィスで 電話</div></div>","setup":"会社で、女の人が 電話で 話して います。","turns":[{"w":"女","t":"はい……来週 火曜の お打ち合わせですね。時間は そのままで、場所だけ、御社から 弊社に 変更、と。かしこまりました。"}],"q":"電話で 変わったのは 何ですか。","cs":["打ち合わせの 場所","打ち合わせの 日","打ち合わせの 時間","打ち合わせの 担当者"],"a":0,"ex":"「時間はそのまま、場所だけ変更」と言っています。日・時間・担当者は変わりません。何が変わったかに注意します。"},

  {"id":"c108","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><circle cx='70' cy='38' r='13' fill='#3C5A78'/><rect x='58' y='50' width='24' height='10' rx='5' fill='#3C5A78'/><circle cx='140' cy='38' r='13' fill='#9CB2C8'/><rect x='128' y='50' width='24' height='10' rx='5' fill='#9CB2C8'/></svg><div class='mtl-cap'>廊下で 立ち話</div></div>","setup":"会社の 廊下で、男の人と 女の人が 話して います。","turns":[{"w":"男","t":"この 書類、コピーして 会議室に 置いといて くれる？"},{"w":"女","t":"はい。あ、その前に、部長が 探して らっしゃいましたよ。"},{"w":"男","t":"え、そうなの。じゃあ 先に 部長の ところへ 行って くる。"}],"q":"男の人は、まず 何を しますか。","cs":["部長の ところへ 行く","書類を コピーする","書類を 会議室に 置く","女の人に 頼む"],"a":0,"ex":"コピーより先に「部長が探していた」と聞き、「先に部長のところへ行く」と言っています。順番に注意します。"},

  {"id":"c109","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><ellipse cx='105' cy='58' rx='68' ry='20' fill='#E4EAF1' stroke='#3C5A78'/><circle cx='60' cy='42' r='10' fill='#3C5A78'/><circle cx='105' cy='36' r='10' fill='#9CB2C8'/><circle cx='150' cy='42' r='10' fill='#3C5A78'/></svg><div class='mtl-cap'>会議室</div></div>","setup":"会議室で、会議が 終わろうと して います。","turns":[{"w":"男","t":"では、本日は ここまで。次回は、再来週の 水曜、午後 二時からです。"},{"w":"女","t":"あの、その 週は 出張の 予定が……。"},{"w":"男","t":"あ、そうか。じゃあ、一週間 早めて、来週の 水曜、同じ 二時に しましょう。"}],"q":"次の 会議は、いつに なりましたか。","cs":["来週の 水曜 午後二時","再来週の 水曜 午後二時","来週の 水曜 午後一時","今週の 水曜 午後二時"],"a":0,"ex":"はじめは再来週の水曜でしたが、出張のため「一週間早めて来週の水曜、同じ二時」に。時間は二時のままです。"},

  {"id":"c110","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><rect x='30' y='58' width='150' height='26' rx='3' fill='#E4EAF1' stroke='#3C5A78'/><rect x='120' y='40' width='46' height='22' rx='3' fill='#4A6B8A'/><circle cx='70' cy='40' r='13' fill='#9CB2C8'/><rect x='58' y='52' width='24' height='10' rx='5' fill='#9CB2C8'/></svg><div class='mtl-cap'>店の レジ</div></div>","setup":"店の レジで、店員と 客が 話して います。","turns":[{"w":"女","t":"お会計は 二千八百円で ございます。"},{"w":"男","t":"じゃあ、この 商品券 三千円分で。"},{"w":"女","t":"ありがとうございます。では、おつりが 二百円で ございます。"}],"q":"客は、いくらの おつりを もらいますか。","cs":["二百円","三千円","二千八百円","おつりは ない"],"a":0,"ex":"三千円の商品券で二千八百円を払うので、おつりは二百円。三千円は商品券の額、二千八百円は代金です。"},

  {"id":"c111","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='200' height='90' viewBox='0 0 200 90' xmlns='http://www.w3.org/2000/svg'><circle cx='100' cy='34' r='15' fill='#9CB2C8'/><rect x='85' y='47' width='30' height='10' rx='5' fill='#9CB2C8'/><path d='M60 68 q-6 -13 7 -18 l5 9 q-7 3 -1 11 z' fill='#4A6B8A'/></svg><div class='mtl-cap'>電話で 話す 女の人</div></div>","setup":"会社で、女の人が 取引先と 電話で 話して います。","turns":[{"w":"女","t":"……そうですか……ええ、ええ……私どもと いたしましても、精一杯 させて いただいたのですが……。はい……では 今回は……。また 何か ございましたら、よろしく お願いいたします。"}],"q":"この 電話は、どんな 話ですか。","cs":["取引が まとまらなかった","取引が うまく まとまった","取引の 内容を 見直す","値段を 下げる ことに した"],"a":0,"ex":"「精一杯したが」「では今回は」「また何かあれば」と、残念そうな言い方から、取引が不成立だったとわかります。成立・見直し・値下げではありません。"},

  {"id":"c112","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><circle cx='70' cy='38' r='13' fill='#3C5A78'/><rect x='58' y='50' width='24' height='10' rx='5' fill='#3C5A78'/><circle cx='140' cy='38' r='13' fill='#9CB2C8'/><rect x='128' y='50' width='24' height='10' rx='5' fill='#9CB2C8'/></svg><div class='mtl-cap'>オフィス</div></div>","setup":"会社で、先輩と 後輩が 明日の 準備に ついて 話して います。","turns":[{"w":"男","t":"明日の 来客、私が 駅まで お迎えに 行くよ。"},{"w":"女","t":"では、私は お茶と 資料の 用意を して おきます。"},{"w":"男","t":"うん。あ、応接室の 予約も、ついでに お願いできる？"},{"w":"女","t":"はい、わかりました。"}],"q":"女の人が する ことは、どれですか。","cs":["お茶と 資料の 用意と、応接室の 予約","駅までの 出迎えと、お茶の 用意","駅までの 出迎えと、応接室の 予約","お茶の 用意だけ"],"a":0,"ex":"駅の出迎えは先輩。女の人は「お茶と資料の用意」に加え「応接室の予約」も頼まれています。誰が何をするかに注意します。"},

  {"id":"c113","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='200' height='90' viewBox='0 0 200 90' xmlns='http://www.w3.org/2000/svg'><circle cx='100' cy='34' r='15' fill='#3C5A78'/><rect x='85' y='47' width='30' height='10' rx='5' fill='#3C5A78'/><path d='M60 68 q-6 -13 7 -18 l5 9 q-7 3 -1 11 z' fill='#4A6B8A'/></svg><div class='mtl-cap'>電話</div></div>","setup":"会社で、男の人が 電話で 話して います。","turns":[{"w":"男","t":"明日の ご訪問の 件ですが……。実は、急な 会議が 入って しまいまして。誠に 申し訳 ございませんが、あさってに 変更 させて いただけないでしょうか。"}],"q":"男の人は、何を お願いして いますか。","cs":["訪問の 日を あさってに 変えたい","訪問を 取りやめたい","訪問の 場所を 変えたい","会議に 出て ほしい"],"a":0,"ex":"「あさってに変更させていただけないか」から、訪問日の変更を頼んでいます。中止・場所変更・会議への誘いではありません。"},

  {"id":"c114","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><circle cx='70' cy='38' r='13' fill='#3C5A78'/><rect x='58' y='50' width='24' height='10' rx='5' fill='#3C5A78'/><circle cx='140' cy='38' r='13' fill='#9CB2C8'/><rect x='128' y='50' width='24' height='10' rx='5' fill='#9CB2C8'/></svg><div class='mtl-cap'>二人の 社員</div></div>","setup":"会社で、二人の 社員が 話して います。","turns":[{"w":"男","t":"例の 件、部長の 鶴の一声で、結局 やる ことに なったよ。"},{"w":"女","t":"そうですか。じゃあ、来月の 展示会には 間に合わせないと ですね。"},{"w":"男","t":"うん。急いで 準備を 始めよう。"}],"q":"二人は、何に ついて 話して いますか。","cs":["展示会の 準備を 始める こと","展示会を 中止する こと","部長への 報告","来月の 会議の 日程"],"a":0,"ex":"「やることになった」「展示会に間に合わせる」「準備を始めよう」から、展示会の準備の話。「鶴の一声」は上の人の一言で決まること。中止・報告・日程ではありません。"},

  {"id":"c115","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><rect x='25' y='58' width='160' height='24' rx='4' fill='#E4EAF1' stroke='#3C5A78'/><circle cx='70' cy='40' r='13' fill='#9CB2C8'/><rect x='58' y='52' width='24' height='8' rx='4' fill='#9CB2C8'/><circle cx='140' cy='40' r='13' fill='#3C5A78'/><rect x='128' y='52' width='24' height='8' rx='4' fill='#3C5A78'/></svg><div class='mtl-cap'>会社の 受付</div></div>","setup":"会社の 受付で、来客と 受付の 人が 話して います。","turns":[{"w":"男","t":"あの、お約束は して いないのですが、営業部の 加藤さんは いらっしゃいますか。近くまで 来た もので。"},{"w":"女","t":"さようで ございますか。ただいま 確認いたしますので、少々 お待ちください。"}],"q":"この 来客の 状況は、どれですか。","cs":["約束なしで 訪ねて 来た","約束の 時間に 来た","道を 尋ねに 来た","荷物を 届けに 来た"],"a":0,"ex":"「お約束はしていないのですが」「近くまで来たもので」から、約束なしの訪問（アポなし）です。約束済み・道案内・配達ではありません。"},

  {"id":"c116","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='200' height='90' viewBox='0 0 200 90' xmlns='http://www.w3.org/2000/svg'><circle cx='100' cy='34' r='15' fill='#9CB2C8'/><rect x='85' y='47' width='30' height='10' rx='5' fill='#9CB2C8'/><path d='M60 68 q-6 -13 7 -18 l5 9 q-7 3 -1 11 z' fill='#4A6B8A'/></svg><div class='mtl-cap'>電話</div></div>","setup":"会社で、女の人が 電話で 注文を 受けて います。","turns":[{"w":"女","t":"ご注文、ありがとうございます。Aセットを 三つ、Bセットを 一つ、ですね。お届けは 明日の 午前中で 承りました。"}],"q":"女の人は、何を して いますか。","cs":["注文を 受けて 内容を 確認して いる","注文を 断って いる","注文を 取り消して いる","商品を すすめて いる"],"a":0,"ex":"「ご注文ありがとうございます」「〜ですね」と復唱し、届け先の日時も確認しています。断り・取消・売り込みではありません。"},

  {"id":"c117","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><rect x='25' y='58' width='160' height='24' rx='4' fill='#E4EAF1' stroke='#3C5A78'/><circle cx='70' cy='40' r='13' fill='#3C5A78'/><rect x='58' y='52' width='24' height='8' rx='4' fill='#3C5A78'/><circle cx='140' cy='40' r='13' fill='#9CB2C8'/><rect x='128' y='52' width='24' height='8' rx='4' fill='#9CB2C8'/></svg><div class='mtl-cap'>店の カウンター</div></div>","setup":"店の カウンターで、客と 店員が 話して います。","turns":[{"w":"男","t":"先週 こちらで 買った 傘なんですが、一度 使った だけで 骨が 折れて しまって。"},{"w":"女","t":"それは 申し訳 ございません。よろしければ、新しい 品と お取り替え いたします。"}],"q":"この 客は、何の ために 来ましたか。","cs":["買った 品の 不具合を 伝える ため","新しい 傘を 買う ため","傘を 注文する ため","傘を 借りる ため"],"a":0,"ex":"「買った傘の骨が折れた」と不具合を伝えに来ています。店員は取り替えを申し出ています。新規購入・注文・貸出ではありません。"},

  {"id":"c118","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><circle cx='70' cy='38' r='13' fill='#3C5A78'/><rect x='58' y='50' width='24' height='10' rx='5' fill='#3C5A78'/><circle cx='140' cy='38' r='13' fill='#9CB2C8'/><rect x='128' y='50' width='24' height='10' rx='5' fill='#9CB2C8'/></svg><div class='mtl-cap'>オフィス</div></div>","setup":"会社で、二人の 社員が 歓迎会の 店に ついて 話して います。","turns":[{"w":"男","t":"歓迎会、駅前の 居酒屋を 考えてたんだけど。"},{"w":"女","t":"あそこ、この前 予約が 取りにくかったです。少し 歩きますが、川沿いの 店は どうですか。個室も ありますし。"},{"w":"男","t":"なるほど。じゃあ、そっちに しよう。"}],"q":"歓迎会は、どこで する ことに なりましたか。","cs":["川沿いの 店","駅前の 居酒屋","会社の 会議室","まだ 決まって いない"],"a":0,"ex":"女の人が川沿いの店を提案し、男の人が「そっちにしよう」と決めています。駅前は最初の案、会議室は出てきません。"},

  {"id":"c119","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='200' height='90' viewBox='0 0 200 90' xmlns='http://www.w3.org/2000/svg'><circle cx='100' cy='34' r='15' fill='#3C5A78'/><rect x='85' y='47' width='30' height='10' rx='5' fill='#3C5A78'/><path d='M60 68 q-6 -13 7 -18 l5 9 q-7 3 -1 11 z' fill='#4A6B8A'/></svg><div class='mtl-cap'>電話</div></div>","setup":"会社で、男の人が 電話に 出て います。","turns":[{"w":"男","t":"はい、佐藤 コーポレーション 営業部で ございます。……はい、渡辺は ただいま 席を 外して おりまして。あのう、失礼ですが……。"}],"q":"男の人は、このあと 何を したがって いますか。","cs":["相手の 名前を 聞く","渡辺を 呼びに 行く","電話を 切る","席を 移る"],"a":0,"ex":"「あのう、失礼ですが……」は「お名前を教えてください」という意味。相手が名乗っていないので、名前を尋ねようとしています。"},

  {"id":"c120","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><circle cx='70' cy='38' r='13' fill='#3C5A78'/><rect x='58' y='50' width='24' height='10' rx='5' fill='#3C5A78'/><circle cx='140' cy='38' r='13' fill='#9CB2C8'/><rect x='128' y='50' width='24' height='10' rx='5' fill='#9CB2C8'/></svg><div class='mtl-cap'>オフィス</div></div>","setup":"会社で、上司と 部下が 話して います。","turns":[{"w":"男","t":"この 企画書、悪くない。ただ、数字の 根拠が 弱いな。ここを 直せば、いける と 思うよ。"},{"w":"女","t":"ありがとうございます。では、根拠の 部分を もう一度 調べて、直します。"}],"q":"上司は、企画書を どう 思って いますか。","cs":["基本は よいが、数字の 根拠を 直せば よい","全部 だめで、作り直しが 必要だ","数字の 根拠だけが すばらしい","まったく 問題が ない"],"a":0,"ex":"「悪くない」と認めたうえで「数字の根拠が弱い、直せばいける」と述べています。全部だめ・根拠が良い・問題なしではありません。"},

  {"id":"c121","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='200' height='90' viewBox='0 0 200 90' xmlns='http://www.w3.org/2000/svg'><circle cx='100' cy='34' r='15' fill='#9CB2C8'/><rect x='85' y='47' width='30' height='10' rx='5' fill='#9CB2C8'/><path d='M60 68 q-6 -13 7 -18 l5 9 q-7 3 -1 11 z' fill='#4A6B8A'/></svg><div class='mtl-cap'>電話</div></div>","setup":"会社で、女の人が 部下からの 電話を 受けて います。","turns":[{"w":"女","t":"はい。……ああ、渋滞で 遅れそうなのね。分かった。先方には、私から 連絡して おくから、気をつけて 来て。無理は しないでね。"}],"q":"女の人は、このあと 何を しますか。","cs":["先方に 遅れる ことを 連絡する","自分が 代わりに 行く","部下を 待たずに 始める","約束を 取り消す"],"a":0,"ex":"「先方には、私から連絡しておく」と言っています。代わりに行く・待たず開始・取消ではありません。"},

  {"id":"c122","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><circle cx='70' cy='38' r='13' fill='#3C5A78'/><rect x='58' y='50' width='24' height='10' rx='5' fill='#3C5A78'/><circle cx='140' cy='38' r='13' fill='#9CB2C8'/><rect x='128' y='50' width='24' height='10' rx='5' fill='#9CB2C8'/></svg><div class='mtl-cap'>オフィス</div></div>","setup":"会社で、男の人と 女の人が 出張の 宿に ついて 話して います。","turns":[{"w":"男","t":"大阪出張の 宿、駅の 近くに 取って おいたよ。"},{"w":"女","t":"ありがとうございます。あ、二日目の 朝は 先方の 工場に 直接 行くので、そちらに 近い ほうが 助かるのですが。"},{"w":"男","t":"なるほど。じゃあ、工場の 近くに 変えて おくよ。"}],"q":"宿は、どこの 近くに しますか。","cs":["工場の 近く","駅の 近く","空港の 近く","会社の 近く"],"a":0,"ex":"はじめは駅の近くでしたが、女の人の希望で「工場の近く」に変更します。駅は最初の案です。"},

  {"id":"c123","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='200' height='90' viewBox='0 0 200 90' xmlns='http://www.w3.org/2000/svg'><circle cx='100' cy='34' r='15' fill='#3C5A78'/><rect x='85' y='47' width='30' height='10' rx='5' fill='#3C5A78'/><path d='M60 68 q-6 -13 7 -18 l5 9 q-7 3 -1 11 z' fill='#4A6B8A'/></svg><div class='mtl-cap'>電話</div></div>","setup":"会社で、男の人が 電話で 話して います。","turns":[{"w":"男","t":"先ほど いただいた メール、拝見しました。ただ、添付の ファイルが、開こうと すると エラーが 出て しまって。お手数ですが、もう一度 お送り いただけますか。"}],"q":"男の人は、相手に 何を 頼んで いますか。","cs":["ファイルを もう一度 送る こと","会社に 来る こと","電話を かけ直す こと","会議を 延ばす こと"],"a":0,"ex":"「添付ファイルが開けない」「もう一度お送りいただけますか」から、ファイルの再送を頼んでいます。来社・かけ直し・延期ではありません。"},

  {"id":"c124","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><rect x='60' y='22' width='40' height='58' rx='2' fill='#E4EAF1' stroke='#3C5A78'/><rect x='110' y='22' width='40' height='58' rx='2' fill='#E4EAF1' stroke='#3C5A78'/><path d='M40 44 l8 -10 l8 10 z' fill='#3C5A78'/><path d='M40 60 l8 10 l8 -10 z' fill='#9CB2C8'/></svg><div class='mtl-cap'>エレベーターの 前</div></div>","setup":"会社の エレベーターの 前で、社員と 来客が 話して います。","turns":[{"w":"女","t":"応接室は 五階で ございます。私が ご案内 いたしますので、どうぞ こちらへ。"},{"w":"男","t":"ありがとうございます。お願いします。"}],"q":"このあと、二人は どう しますか。","cs":["一緒に 五階へ 上がる","一階で 別れる","外へ 出る","受付へ 戻る"],"a":0,"ex":"「五階でございます」「ご案内いたします」「こちらへ」から、社員が来客を連れて一緒に五階へ向かいます。"},

  {"id":"c125","sec":"状況をつかむ","material":"<div class='mtl-scene'><svg width='210' height='92' viewBox='0 0 210 92' xmlns='http://www.w3.org/2000/svg'><ellipse cx='105' cy='58' rx='68' ry='20' fill='#E4EAF1' stroke='#3C5A78'/><circle cx='60' cy='42' r='10' fill='#3C5A78'/><circle cx='105' cy='36' r='10' fill='#9CB2C8'/><circle cx='150' cy='42' r='10' fill='#3C5A78'/></svg><div class='mtl-cap'>会議室</div></div>","setup":"会議で、男の人が 資料を 配りながら 話して います。","turns":[{"w":"男","t":"では、お手元の 資料の 二ページ目を ご覧ください。……あ、失礼、いま 配って いる 青い 紙の ほうです。白い 紙では ありません。"}],"q":"参加者は、どの 紙を 見ますか。","cs":["青い 紙","白い 紙","二ページ目の 表","手元の 全部"],"a":0,"ex":"「いま配っている青い紙のほう。白い紙ではありません」と言い直しています。見るのは青い紙です。"},

  {"id":"c211","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>会議室</th><th>定員</th><th>投影機</th><th>14時</th></tr><tr><td class='l'>A室</td><td>6名</td><td>有</td><td>○</td></tr><tr><td class='l'>B室</td><td>10名</td><td>無</td><td>○</td></tr><tr><td class='l'>C室</td><td>12名</td><td>有</td><td>×</td></tr><tr><td class='l'>D室</td><td>10名</td><td>有</td><td>○</td></tr></table><div style='font-size:11px;color:#6B6560;margin-top:4px'>○=空き ×=予約済み</div>","setup":"会社で、男の人が 会議室の 表を 見ながら 話して います。","turns":[{"w":"男","t":"14時に、8人で 打ち合わせを したいんだ。プロジェクターも 使うから、投影機の ある 部屋が いいな。"}],"q":"条件に 合う 会議室は、どれですか。","cs":["D室","A室","B室","C室"],"a":0,"ex":"「14時に空き・8人以上・投影機あり」の全部に合うのはD室。A室は定員6で不足、B室は投影機なし、C室は14時が予約済みです。"},

  {"id":"c212","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>商品</th><th>重さ</th><th>値段</th></tr><tr><td>A</td><td>1.5kg</td><td>9,000円</td></tr><tr><td>B</td><td>0.9kg</td><td>12,000円</td></tr><tr><td>C</td><td>1.1kg</td><td>8,000円</td></tr></table>","setup":"店で、女の人が カタログを 見ながら 話して います。","turns":[{"w":"女","t":"毎日 かばんに 入れて 持ち歩くので、軽い ほうが いいな。でも、一万円は 超えたくないの。"}],"q":"女の人に 合う 商品は、どれですか。","cs":["商品C","商品B","商品A","合う ものが ない"],"a":0,"ex":"「軽い」かつ「一万円以下」の両方に合うのはC（1.1kg・8,000円）。Bは一番軽いが12,000円で予算オーバー、Aは重めです。"},

  {"id":"c213","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>プラン</th><th>月額</th><th>データ量</th></tr><tr><td class='l'>ライト</td><td>1,000円</td><td>3GB</td></tr><tr><td class='l'>標準</td><td>2,500円</td><td>20GB</td></tr><tr><td class='l'>大容量</td><td>4,000円</td><td>無制限</td></tr></table>","setup":"携帯電話の 店で、男の人が プランを えらんで います。","turns":[{"w":"男","t":"外で 動画を たくさん 見るので、データ量を 気に せず 使いたいです。値段は 気に しません。"}],"q":"男の人に 合う プランの 月額は、いくらですか。","cs":["4,000円","2,500円","1,000円","3,000円"],"a":0,"ex":"「データ量を気にせず」＝無制限の「大容量」。表よりその月額は4,000円です。3,000円は表にない数字です。"},

  {"id":"c214","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>発車</th><th>種類</th><th>行き先</th></tr><tr><td>9:55</td><td>普通</td><td>本社前</td></tr><tr><td>10:05</td><td>普通</td><td>本社前</td></tr><tr><td>10:15</td><td class='l'><span class='mtl-hl'>快速</span></td><td>本社前</td></tr><tr><td>10:30</td><td>快速</td><td>本社前</td></tr></table>","setup":"駅で、男の人が 時刻表を 見ながら 話して います。","turns":[{"w":"男","t":"急いで いるから、10時 すぎに 出る 中で、いちばん 早い 快速に 乗ろう。普通は 時間が かかるからね。"}],"q":"男の人が 乗る 電車は、何時 発ですか。","cs":["10:15","10:05","10:30","9:55"],"a":0,"ex":"「10時すぎ・いちばん早い快速」に合うのは10:15。10:05は普通、10:30は次の快速、9:55は10時前です。"},

  {"id":"c215","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>品名</th><th>単価</th><th>数量</th></tr><tr><td class='l'>コピー用紙</td><td>400円</td><td>6</td></tr><tr><td class='l'>ボールペン</td><td>100円</td><td>10</td></tr><tr><td class='l'>ファイル</td><td>250円</td><td>4</td></tr></table>","setup":"会社で、女の人が 注文書を 見ながら 話して います。","turns":[{"w":"女","t":"支払う 合計金額が 大きい 品を、間違えない ように しないと ね。一番 お金が かかる のは どれかな。"}],"q":"合計金額が いちばん 高い 品は、どれですか。","cs":["コピー用紙","ボールペン","ファイル","どれも 同じ"],"a":0,"ex":"合計は 用紙400×6＝2,400円、ペン100×10＝1,000円、ファイル250×4＝1,000円。いちばん高いのはコピー用紙です。数量が多いペンにひっかからないように。"},

  {"id":"c216","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>階</th><th>部署</th></tr><tr><td>4階</td><td class='l'>役員室・応接室</td></tr><tr><td>3階</td><td class='l'>総務部・人事部</td></tr><tr><td>2階</td><td class='l'>経理部</td></tr><tr><td>1階</td><td class='l'>受付・営業部</td></tr></table>","setup":"会社で、先輩が 新入社員に 用事を 頼んで います。","turns":[{"w":"男","t":"この 精算の 書類、経理に 出して きて くれる？総務じゃ ないから、間違えないでね。"}],"q":"新入社員は、何階へ 行けば よいですか。","cs":["2階","3階","1階","4階"],"a":0,"ex":"経理部は案内図より「2階」。3階は総務・人事です。「総務じゃない」の念押しにも注意します。"},

  {"id":"c217","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>会社</th><th>上期</th><th>下期</th><th>増減率</th></tr><tr><td>P社</td><td>20</td><td>15</td><td class='mtl-hl'>▲25%</td></tr><tr><td>Q社</td><td>18</td><td>19</td><td>+6%</td></tr><tr><td>R社</td><td>14</td><td>20</td><td>+43%</td></tr><tr><td>S社</td><td>13</td><td>12</td><td>▲8%</td></tr></table><div style='font-size:11px;color:#6B6560;margin-top:4px'>▲は マイナス（減少）を 表します</div>","setup":"会議で、女の人が 表を 見せながら 話して います。","turns":[{"w":"女","t":"この 中で、下期の 売上が 上期を いちばん 大きく 下回った 会社は どこか、見て みましょう。"}],"q":"下期が 上期を いちばん 大きく 下回った 会社は、どれですか。","cs":["P社","S社","Q社","R社"],"a":0,"ex":"「下回った」＝▲（マイナス）の会社。P社▲25%とS社▲8%のうち、大きいのはP社。Q社・R社は増えています（プラス）。"},

  {"id":"c218","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>氏名</th><th>筆記</th><th>面接</th></tr><tr><td class='l'>合格基準</td><td>70</td><td>70</td></tr><tr><td class='l'>青木</td><td>85</td><td>75</td></tr><tr><td class='l'>石田</td><td>90</td><td>60</td></tr><tr><td class='l'>上田</td><td>65</td><td>80</td></tr></table><div style='font-size:11px;color:#6B6560;margin-top:4px'>両方 70点 以上で 合格</div>","setup":"会社で、男の人が 昇進試験の 結果を 見て 話して います。","turns":[{"w":"男","t":"筆記と 面接、どちらも 70点 以上 取れた 人だけが 合格だよ。一つでも 70点 未満だと 不合格。"}],"q":"合格した 人は、だれですか。","cs":["青木さん","石田さん","上田さん","全員"],"a":0,"ex":"両方70点以上は青木さん（85・75）だけ。石田さんは面接60、上田さんは筆記65で、それぞれ基準に届かず不合格です。"},

  {"id":"c219","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>券種</th><th>料金</th></tr><tr><td class='l'>大人</td><td>1,200円</td></tr><tr><td class='l'>子ども</td><td>600円</td></tr><tr><td class='l'>65歳以上</td><td>900円</td></tr></table>","setup":"受付で、女の人が 料金表を 見ながら 話して います。","turns":[{"w":"女","t":"大人 二人と、子ども 一人 です。ええと、合計は……。"}],"q":"合計金額は、いくらですか。","cs":["3,000円","1,800円","2,400円","1,200円"],"a":0,"ex":"大人1,200×2＝2,400円、子ども600×1＝600円で、合計3,000円。2,400円は大人だけ、1,800円は大人1＋子ども1の額です。"},

  {"id":"c220","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>セット</th><th>内容</th><th>値段</th></tr><tr><td>A</td><td class='l'>コーヒー＋トースト</td><td>500円</td></tr><tr><td>B</td><td class='l'>紅茶＋ケーキ</td><td>700円</td></tr><tr><td>C</td><td class='l'>ジュース＋サンド</td><td>800円</td></tr></table>","setup":"喫茶店で、男の人と 女の人が メニューを 見て 話して います。","turns":[{"w":"女","t":"私、甘い ものが 食べたいから、ケーキの セットに するね。"},{"w":"男","t":"じゃあ 僕は、軽く パンで いいや。いちばん 安いのに しよう。"}],"q":"男の人は、どの セットを 注文しますか。","cs":["Aセット","Bセット","Cセット","注文しない"],"a":0,"ex":"男の人は「パンで、いちばん安いの」。表よりA（コーヒー＋トースト・500円）。Bはケーキで女の人の分です。"},

  {"id":"c221","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>時間</th><th>会議</th><th>場所</th></tr><tr><td>10:00</td><td class='l'>企画会議</td><td>第1会議室</td></tr><tr><td>13:00</td><td class='l'>営業会議</td><td>第3会議室</td></tr><tr><td>15:30</td><td class='l'>部内 打合せ</td><td>第2会議室</td></tr></table>","setup":"会社で、女の人が 今日の 予定表を 見ながら 話して います。","turns":[{"w":"女","t":"お昼を はさんで、午後 いちばん 最初の 会議に 出ないと。資料は そろって いるかな。"}],"q":"女の人が 出る 会議の 場所は、どこですか。","cs":["第3会議室","第1会議室","第2会議室","応接室"],"a":0,"ex":"「午後いちばん最初」＝13:00の営業会議。表より場所は第3会議室。第1は午前、第2は15:30です。"},

  {"id":"c222","sec":"資料を見て聞く","material":"<div class='mtl-notice'><div class='nt-t'>ゴミ 分別の お願い</div>燃える ゴミ：月・木<br>びん・かん：<span class='mtl-hl'>水</span><br>ペットボトル：金<br>紙・段ボール：火</div>","setup":"会社で、男の人が 掲示を 見ながら 同僚に 聞いて います。","turns":[{"w":"男","t":"この 飲み終わった 缶、燃える ゴミじゃ ないよね。何曜日に 出せば いいのかな。"}],"q":"缶は、何曜日に 出しますか。","cs":["水曜日","月曜日","金曜日","火曜日"],"a":0,"ex":"缶は「びん・かん：水」。月・木は燃えるゴミ、金はペットボトル、火は紙・段ボールです。"},

  {"id":"c223","sec":"資料を見て聞く","material":"<div class='mtl-mail'>件名：社内 研修の ご案内\n\n・日時：来週 月曜 9時〜\n・場所：3階 大会議室\n・持ち物：<span class='mtl-hl'>筆記用具・印鑑</span>\n（昼食・パソコンは 用意します）\n　　　　　　　　　　総務部</div>","setup":"会社で、男の人が 研修の 案内メールを 見ながら 同僚に 聞いて います。","turns":[{"w":"男","t":"この 研修、自分で 持って いく 物 って あった かな。"}],"q":"研修に、何を 持って いきますか。","cs":["筆記用具と 印鑑","昼食と パソコン","筆記用具と 昼食","何も 要らない"],"a":0,"ex":"メールに「持ち物：筆記用具・印鑑」とあります。昼食とパソコンは用意されるので、持っていきません。"},

  {"id":"c224","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>店</th><th>駅から</th><th>個室</th><th>予算</th></tr><tr><td class='l'>あおば</td><td>5分</td><td>無</td><td>4千円</td></tr><tr><td class='l'>みなと</td><td>3分</td><td>有</td><td>6千円</td></tr><tr><td class='l'>さくら</td><td>4分</td><td>有</td><td>4千円</td></tr></table>","setup":"会社で、女の人が 店の 一覧を 見ながら 話して います。","turns":[{"w":"女","t":"歓迎会の お店、個室が あって、一人 五千円までの ところが いいな。駅から 近い ほうが 助かるけど。"}],"q":"女の人の 希望に 合う 店は、どれですか。","cs":["さくら","みなと","あおば","合う 店が ない"],"a":0,"ex":"「個室あり・五千円まで」に合うのは「さくら」（個室有・4千円）。みなとは個室ありだが6千円で予算オーバー、あおばは個室なしです。"},

  {"id":"c225","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>順位</th><th>男性</th><th>女性</th></tr><tr><td>1</td><td>貯金</td><td>貯金</td></tr><tr><td>2</td><td class='l'>スーツ</td><td class='l'>旅行</td></tr><tr><td>3</td><td class='l'>旅行</td><td class='l'>服</td></tr><tr><td>4</td><td>車の 用品</td><td>バッグ</td></tr></table>","setup":"会議で、男の人が アンケートの 表を 見せながら 話して います。","turns":[{"w":"男","t":"ボーナスの 使い道です。貯金を のぞくと、男性も 女性も、共通して 上位に 入って いる ものが 一つ ありますね。"}],"q":"貯金を のぞいて、男女 共通して 多い ものは、何ですか。","cs":["旅行","スーツ","服","バッグ"],"a":0,"ex":"貯金をのぞくと、男性3位・女性2位の「旅行」が両方に入っています。スーツ・車用品は男性だけ、服・バッグは女性だけです。"},

  {"id":"c226","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>会議室</th><th>椅子</th><th>使用可</th></tr><tr><td class='l'>第1</td><td>20</td><td>13:00-14:00</td></tr><tr><td class='l'>第2</td><td>6</td><td>13:00-16:00</td></tr><tr><td class='l'>第3</td><td>12</td><td>15:00-18:00</td></tr><tr><td class='l'>第4</td><td>10</td><td>12:00-15:00</td></tr></table>","setup":"会社で、女の人が 会議室の 表を 見て 話して います。","turns":[{"w":"女","t":"13時から 90分、8人で 使いたいの。時間内に 収まって、椅子も 足りる 部屋は どこかな。"}],"q":"条件に 合う 会議室は、どれですか。","cs":["第4","第1","第2","第3"],"a":0,"ex":"13時から90分（＝14時半まで）・椅子8以上に合うのは第4（10席・12-15時）。第1は14時までで足りず、第2は椅子6で不足、第3は15時からです。"},

  {"id":"c227","sec":"資料を見て聞く","material":"<svg width='210' height='110' viewBox='0 0 210 110' xmlns='http://www.w3.org/2000/svg'><line x1='0' y1='58' x2='210' y2='58' stroke='#bbb' stroke-width='8'/><rect x='20' y='20' width='48' height='26' rx='3' fill='#E4EAF1' stroke='#3C5A78'/><text x='44' y='37' font-size='11' text-anchor='middle' fill='#3C5A78'>銀行</text><rect x='142' y='20' width='48' height='26' rx='3' fill='#E4EAF1' stroke='#3C5A78'/><text x='166' y='37' font-size='11' text-anchor='middle' fill='#3C5A78'>薬局</text><rect x='84' y='70' width='46' height='26' rx='3' fill='#FAEEDA' stroke='#854F0B'/><text x='107' y='87' font-size='11' text-anchor='middle' fill='#854F0B'>駅</text></svg>","setup":"駅の 前で、男の人が 地図を 見ながら 電話で 話して います。","turns":[{"w":"男","t":"今 駅を 出た ところです。大通りを わたって、右の ほうに 行けば いいんですね。"}],"q":"男の人が 向かって いるのは、どこですか。","cs":["薬局","銀行","駅","コンビニ"],"a":0,"ex":"大通りの向こう、左が銀行、右が薬局。「右のほうに行く」ので薬局です。左右を聞き分けます。"},

  {"id":"c228","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>部屋</th><th>10時</th><th>11時</th><th>13時</th></tr><tr><td class='l'>A室</td><td>×</td><td>○</td><td>○</td></tr><tr><td class='l'>B室</td><td>○</td><td>×</td><td>×</td></tr><tr><td class='l'>C室</td><td>×</td><td>○</td><td>×</td></tr></table><div style='font-size:11px;color:#6B6560;margin-top:4px'>○=空き ×=予約済み</div>","setup":"会社で、男の人が 予約表を 見ながら 話して います。","turns":[{"w":"男","t":"午前と 午後、両方 使いたいんだ。11時と 13時、どちらも 空いて いる 部屋は あるかな。"}],"q":"11時と 13時、両方 空いて いる 部屋は、どれですか。","cs":["A室","B室","C室","どれも ない"],"a":0,"ex":"11時○かつ13時○はA室だけ。B室は11時×、C室は13時×です。両方が空いている部屋を探します。"},

  {"id":"c229","sec":"資料を見て聞く","material":"<div class='mtl-mail'>件名：お見積り\n\nお見積り金額：<span class='mtl-hl'>200,000円</span>\n納期：2週間\n※20個以上の ご注文で 1割 引き</div>","setup":"会社で、女の人が 見積書の メールを 見せながら 上司に 相談して います。","turns":[{"w":"女","t":"A社への お見積り、20万円ですが、今回は 25個 の 注文です。"},{"w":"男","t":"20個 以上だから、1割 引きが 使えるね。じゃあ、その 金額で 出して。"}],"q":"A社へ 出す 金額は、いくらに なりますか。","cs":["180,000円","200,000円","160,000円","220,000円"],"a":0,"ex":"25個は20個以上なので1割引き。20万円の1割（2万円）を引いて18万円です。20万円は割引前の額です。"},

  {"id":"c230","sec":"資料を見て聞く","material":"<table class='mtl-t'><tr><th>宛先</th><th>印</th></tr><tr><td class='l'>東西商事</td><td class='mtl-hl'>★急ぎ</td></tr><tr><td class='l'>南北物産</td><td>—</td></tr><tr><td class='l'>山川工業</td><td class='mtl-hl'>★急ぎ</td></tr></table>","setup":"会社で、女の人が 発送リストを 見ながら 男の人に 聞いて います。","turns":[{"w":"男","t":"★印が ついて いる 急ぎの ところは 速達、印の ない ところは 普通郵便で お願い。"}],"q":"速達で 送るのは、どこですか。","cs":["東西商事と 山川工業","南北物産だけ","東西商事だけ","三つ とも 全部"],"a":0,"ex":"★印（急ぎ）は東西商事と山川工業で、そこが速達。印のない南北物産は普通郵便です。どこに印があるかを見ます。"},

  {"id":"c311","sec":"総合的に聞く","material":"<div class='mtl-mail'>【 電話メモ 】\n○○課長 へ\n\n企画部の 森さん より お電話。\n「明日の 会議の 件。営業からの データを 受け取り次第、部長室へ 来て ほしい」\nとの ことです。</div>","setup":"外出先から 戻って 席に つくと、メモが 置いて ありました。メモを 見て、まず はじめに どう しますか。","turns":[{"w":"男","t":"（メモを 読んで います）"}],"q":"課長は、まず はじめに 何を しますか。","cs":["営業からの データを 待つ","部長室へ 行く","森さんに 電話する","会議の 資料を 作る"],"a":0,"ex":"「営業からのデータを受け取り次第、部長室へ」＝データを受け取ってから部長室へ。だから、まずは営業からのデータを待ちます。順番に注意します。"},

  {"id":"c312","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th>時間</th><th>予定</th></tr><tr><td>10:00</td><td class='l'>A社 訪問</td></tr><tr><td>13:00</td><td class='l'>社内 会議</td></tr><tr><td>15:00</td><td class='l'>資料 作成</td></tr></table>","setup":"会社で、男の人と 女の人が 今日の 予定表を 見ながら 話して います。","turns":[{"w":"男","t":"13時からの 社内会議だけど、部長の 都合で、二時間 遅く なったよ。"},{"w":"女","t":"じゃあ、15時 からですね。あ、でも その 時間は 資料作成の 予定が……。"},{"w":"男","t":"資料は 明日で いいから、会議を 優先して。"}],"q":"社内会議は、何時からに なりましたか。","cs":["15時","13時","17時","10時"],"a":0,"ex":"13時から二時間遅れて15時に。資料作成は明日に回します。13時は元の時間、10時はA社訪問です。"},

  {"id":"c313","sec":"総合的に聞く","material":"<svg width='220' height='120' viewBox='0 0 220 120' xmlns='http://www.w3.org/2000/svg'><line x1='24' y1='100' x2='210' y2='100' stroke='#ccc'/><rect x='36' y='72' width='28' height='28' fill='#9CB2C8'/><text x='50' y='114' font-size='10' text-anchor='middle' fill='#6B6560'>1期</text><rect x='82' y='60' width='28' height='40' fill='#9CB2C8'/><text x='96' y='114' font-size='10' text-anchor='middle' fill='#6B6560'>2期</text><rect x='128' y='40' width='28' height='60' fill='#9CB2C8'/><text x='142' y='114' font-size='10' text-anchor='middle' fill='#6B6560'>3期</text><rect x='174' y='52' width='28' height='48' fill='#3C5A78'/><text x='188' y='114' font-size='10' text-anchor='middle' fill='#6B6560'>4期</text></svg>","setup":"会議で、男の人が グラフを 見せながら 説明して います。","turns":[{"w":"男","t":"昨年の 売上です。順調に 伸びて、三期目で ピークを 迎えました。ただ、四期は 少し 落ち込んで しまいました。"}],"q":"売上が いちばん 高かったのは、どの 期ですか。","cs":["3期","4期","2期","1期"],"a":0,"ex":"「三期目でピーク、四期は落ち込んだ」との説明どおり、グラフでも3期がいちばん高いです。4期は下がっています。"},

  {"id":"c314","sec":"総合的に聞く","material":"<div class='mtl-mail'>件名：お見積り\n\nお見積り金額：<span class='mtl-hl'>150,000円</span>\n納期：ご注文から 10日\n※お支払いが 現金の 場合、5% 引き</div>","setup":"会社で、女の人が 見積りの メールを 見せながら、上司に 相談して います。","turns":[{"w":"女","t":"B社への お見積り、15万円です。先方は 現金で 払うと おっしゃって います。"},{"w":"男","t":"現金なら 5% 引きだね。じゃあ、割引後の 金額で 出して。"}],"q":"B社へ 出す 金額は、いくらに なりますか。","cs":["142,500円","150,000円","145,000円","135,000円"],"a":0,"ex":"現金払いで5%引き。15万円の5%（7,500円）を引いて142,500円です。15万円は割引前、135,000円は1割引きの誤りです。"},

  {"id":"c315","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th>日</th><th>午前</th><th>午後</th></tr><tr><td>1日目</td><td class='l'>移動</td><td class='l'>支店で 会議</td></tr><tr><td>2日目</td><td class='l'>工場 見学</td><td class='l'>帰社</td></tr></table>","setup":"会社で、男の人と 女の人が 出張の 予定を 見て 話して います。","turns":[{"w":"女","t":"2日目の 午前は、工場 見学の 予定でしたね。"},{"w":"男","t":"それが、先方の 都合で 見学は 取りやめに なって。代わりに、支店で もう一度 打ち合わせを する ことに なったよ。"}],"q":"2日目の 午前は、何を する ことに なりましたか。","cs":["支店で 打ち合わせ","工場 見学","移動","帰社"],"a":0,"ex":"予定表では工場見学ですが、会話で「見学は取りやめ、支店で打ち合わせ」に変更されました。会話での変更に注意します。"},

  {"id":"c316","sec":"総合的に聞く","material":"<div class='mtl-notice'><div class='nt-t'>アンケート ご協力の お願い</div>所要：約5分<br>方法：下の QRコード<br>締切：<span class='mtl-hl'>今週 木曜</span></div>","setup":"会社で、男の人が アンケートの 用紙を 見せながら 話して います。","turns":[{"w":"男","t":"この お客様 アンケート、締切は 用紙には 木曜と ありますが、回答が 少ないので、一日 延ばして 金曜まで に する そうです。"},{"w":"女","t":"では、金曜 締切で、みんなに 知らせますね。"}],"q":"新しい 締切は、いつですか。","cs":["今週 金曜","今週 木曜","来週 木曜","今日"],"a":0,"ex":"用紙は木曜ですが、会話で「一日延ばして金曜まで」に変更。木曜は元の締切です。資料と会話の違いに注意します。"},

  {"id":"c317","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th>重視する 点</th><th>割合</th></tr><tr><td class='l'>使いやすさ</td><td>42%</td></tr><tr><td class='l'>値段</td><td>30%</td></tr><tr><td class='l'>デザイン</td><td>18%</td></tr><tr><td class='l'>その他</td><td>10%</td></tr></table>","setup":"会議で、女の人が アンケートの 結果を 見せながら 説明して います。","turns":[{"w":"女","t":"お客様が 商品を えらぶ とき、いちばん 多くの 方が 重視すると 答えた 点を 中心に、改善を 進めて まいります。"}],"q":"改善で いちばん 重視するのは、何ですか。","cs":["使いやすさ","値段","デザイン","その他"],"a":0,"ex":"「いちばん多くの方が重視」＝表で割合が最も高い「使いやすさ（42%）」。値段30%より高いです。"},

  {"id":"c318","sec":"総合的に聞く","material":"<svg width='210' height='96' viewBox='0 0 210 96' xmlns='http://www.w3.org/2000/svg'><rect x='72' y='10' width='66' height='18' rx='3' fill='#FAEEDA' stroke='#854F0B'/><text x='105' y='23' font-size='10' text-anchor='middle' fill='#854F0B'>入口</text><rect x='30' y='50' width='44' height='30' rx='3' fill='#E4EAF1' stroke='#3C5A78'/><text x='52' y='69' font-size='11' text-anchor='middle' fill='#3C5A78'>1番</text><rect x='83' y='50' width='44' height='30' rx='3' fill='#E4EAF1' stroke='#3C5A78'/><text x='105' y='69' font-size='11' text-anchor='middle' fill='#3C5A78'>2番</text><rect x='136' y='50' width='44' height='30' rx='3' fill='#E4EAF1' stroke='#3C5A78'/><text x='158' y='69' font-size='11' text-anchor='middle' fill='#3C5A78'>3番</text></svg>","setup":"展示会の 会場で、係の 人が ブースの 場所を 説明して います。","turns":[{"w":"女","t":"うちの ブースは、入口から 入って、いちばん 手前の 左側です。"},{"w":"男","t":"手前の 左、ですね。分かりました。"}],"q":"この 会社の ブースは、何番ですか。","cs":["1番","3番","2番","入口の 前"],"a":0,"ex":"入口から入っていちばん手前の左は、図の左端の1番です。3番はいちばん奥（右）です。"},

  {"id":"c319","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th></th><th>値段</th><th>納期</th></tr><tr><td>P社</td><td>安い</td><td class='l'>3週間</td></tr><tr><td>Q社</td><td>普通</td><td class='l'>1週間</td></tr></table>","setup":"会社で、二人が 二つの 会社の 比較表を 見て 話して います。","turns":[{"w":"男","t":"P社は 安いんだけど、届くまで 3週間 かかるんだ。"},{"w":"女","t":"今回は 急ぎだから、少し 高くても、早く 届く ほうが いいですよ。"},{"w":"男","t":"そうだね。じゃあ、そっちに しよう。"}],"q":"二人は、どちらの 会社に 決めましたか。","cs":["Q社","P社","どちらも やめる","まだ 決めない"],"a":0,"ex":"「急ぎだから早く届くほうがいい」で合意。表より納期1週間はQ社です。P社は安いが3週間かかります。"},

  {"id":"c320","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th>工程</th><th>締切</th></tr><tr><td class='l'>下書き</td><td>月曜</td></tr><tr><td class='l'>見直し</td><td>水曜</td></tr><tr><td class='l'>提出</td><td>金曜</td></tr></table>","setup":"会社で、上司と 部下が 作業の 予定表を 見て 話して います。","turns":[{"w":"男","t":"提出は 金曜だけど、会議が 二日 早まって 水曜に なったんだ。"},{"w":"女","t":"では、水曜の 会議までに 出せる よう、見直しを 二日 早めて、月曜に します。"}],"q":"見直しは、いつまでに 終わらせますか。","cs":["月曜","水曜","金曜","火曜"],"a":0,"ex":"会議が水曜に早まったため、見直しを予定表の水曜から二日早めて「月曜」に。金曜は元の提出日です。"},

  {"id":"c321","sec":"総合的に聞く","material":"<div class='mtl-mail'>【 お届けメモ 】\nお届け品：展示会用 ポスター・垂れ幕\n\n・ポスター → ロビーの 掲示板に 貼る\n・垂れ幕 → 後日、広報担当が 伺い、ご相談\n　　　　　　　　　　○○物産 中山</div>","setup":"荷物が 届き、中に メモが 入って いました。会館の 人は、これを 見て どう しますか。","turns":[{"w":"男","t":"（メモを 読んで います）"}],"q":"会館の 人は、どう しますか。","cs":["ポスターは ロビーに 貼り、垂れ幕は 広報担当と 相談する","ポスターも 垂れ幕も 広報担当と 相談する","ポスターは 広報担当と 相談し、垂れ幕は ロビーに 貼る","ポスターも 垂れ幕も ロビーに 貼る"],"a":0,"ex":"メモは「ポスター→ロビーの掲示板」「垂れ幕→広報担当と相談」。二つの品で扱いが違う点に注意します。"},

  {"id":"c322","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th>時間</th><th>課長</th><th>担当者</th></tr><tr><td>10時</td><td class='l'>外出</td><td class='l'>在席</td></tr><tr><td>13時</td><td class='l'>在席</td><td class='l'>会議</td></tr><tr><td>15時</td><td class='l'>在席</td><td class='l'>在席</td></tr></table>","setup":"会社で、明日、取引先が 来社し、課長と 担当者の 3人で 打ち合わせを します。予定表を 見て 話して います。","turns":[{"w":"女","t":"明日の 打ち合わせ、課長と 担当者、二人とも 手が 空いて いる 時間じゃ ないと ですね。"},{"w":"男","t":"そうだね。会議や 外出が ない 時間に しよう。"}],"q":"打ち合わせは、何時に すれば よいですか。","cs":["15時","10時","13時","どの 時間でも よい"],"a":0,"ex":"課長・担当者の両方が「在席」なのは15時だけ。10時は課長が外出、13時は担当者が会議です。二人とも空いている時間を探します。"},

  {"id":"c323","sec":"総合的に聞く","material":"<div class='mtl-mail'>【 伝言メモ 】\n△△様 へ\n\n取引先の 林様 より お電話。\n「見積書を 確認したい。折り返しの 前に、まず メールで 送って ほしい」\nとの ことです。</div>","setup":"席に 戻ると、伝言メモが ありました。メモを 見て、まず はじめに どう しますか。","turns":[{"w":"女","t":"（メモを 読んで います）"}],"q":"まず はじめに、何を しますか。","cs":["見積書を メールで 送る","林様に 折り返し 電話する","見積書を 作り直す","上司に 報告する"],"a":0,"ex":"「折り返しの前に、まずメールで送ってほしい」から、最初にすることはメールでの送付。電話はそのあとです。"},

  {"id":"c324","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th>ツアー</th><th>出発</th><th>料金</th><th>空き</th></tr><tr><td class='l'>山なみ</td><td>新宿 8:00</td><td>9,800円</td><td>有</td></tr><tr><td class='l'>湖めぐり</td><td>渋谷 8:30</td><td>8,500円</td><td>有</td></tr><tr><td class='l'>紅葉狩り</td><td>新宿 9:00</td><td>9,500円</td><td>無</td></tr></table>","setup":"会社で、女の人が 日帰りツアーの 表を 見ながら 話して います。","turns":[{"w":"女","t":"新宿発で、一万円以下、しかも まだ 空きが ある ツアーが いいな。"}],"q":"条件に 合う ツアーは、どれですか。","cs":["山なみ","湖めぐり","紅葉狩り","合う ものが ない"],"a":0,"ex":"「新宿発・一万円以下・空きあり」の全部に合うのは「山なみ」。湖めぐりは渋谷発、紅葉狩りは空きなしです。"},

  {"id":"c325","sec":"総合的に聞く","material":"<svg width='220' height='120' viewBox='0 0 220 120' xmlns='http://www.w3.org/2000/svg'><line x1='24' y1='100' x2='210' y2='100' stroke='#ccc'/><rect x='40' y='44' width='24' height='56' fill='#9CB2C8'/><text x='52' y='114' font-size='10' text-anchor='middle' fill='#6B6560'>4月</text><rect x='80' y='56' width='24' height='44' fill='#9CB2C8'/><text x='92' y='114' font-size='10' text-anchor='middle' fill='#6B6560'>5月</text><rect x='120' y='68' width='24' height='32' fill='#9CB2C8'/><text x='132' y='114' font-size='10' text-anchor='middle' fill='#6B6560'>6月</text><rect x='160' y='30' width='24' height='70' fill='#3C5A78'/><text x='172' y='114' font-size='10' text-anchor='middle' fill='#6B6560'>7月</text></svg>","setup":"会議で、男の人が 来客数の グラフを 見せながら 説明して います。","turns":[{"w":"男","t":"上半期の 来客数です。春先は 多かったのですが、そのあと だんだん 減って いきました。ところが、夏の セールを 始めた 月に、また 大きく 増えました。"}],"q":"来客数が いちばん 多かったのは、何月ですか。","cs":["7月","4月","5月","6月"],"a":0,"ex":"「だんだん減り、夏のセールの月にまた大きく増えた」との説明どおり、グラフでも7月が最も高いです。4月は春先で二番目です。"},

  {"id":"c326","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th>社員</th><th>午前の 予定</th></tr><tr><td class='l'>岩川</td><td>—</td></tr><tr><td class='l'>石田</td><td>取引先へ 立ち寄り → 10:30 出社</td></tr><tr><td class='l'>岡山</td><td>出張（大阪）</td></tr></table>","setup":"会社で、女の人が 部の 予定表を 見ながら 話して います。","turns":[{"w":"女","t":"今日、始業の 9時に 会社に いない 人は だれか、確認して おきたいの。ただ、出張の 人は 別扱いね。"}],"q":"今日、会社に 遅れて 出社する 人は、だれですか。","cs":["石田さん","岩川さん","岡山さん","いない"],"a":0,"ex":"「立ち寄り」は出社の途中で別の場所へ寄ること。石田さんは立ち寄って10:30出社なので遅れます。岡山さんは出張で別扱いです。"},

  {"id":"c327","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th>部屋</th><th>広さ</th><th>マイク</th></tr><tr><td class='l'>大ホール</td><td>200席</td><td>有</td></tr><tr><td class='l'>中会議室</td><td>80席</td><td>有</td></tr><tr><td class='l'>小会議室</td><td>30席</td><td>無</td></tr></table>","setup":"会社で、男の人と 女の人が 講演会の 会場に ついて 話して います。","turns":[{"w":"女","t":"講演会、参加者は 60人くらいの 見込みです。"},{"w":"男","t":"マイクは 使いたいね。大ホールだと 広すぎるから、ちょうど いい 広さで マイクの ある 部屋に しよう。"}],"q":"講演会は、どの 部屋で しますか。","cs":["中会議室","大ホール","小会議室","決められない"],"a":0,"ex":"60人が入り、マイクがあり、広すぎない部屋＝中会議室（80席・マイク有）。大ホールは広すぎ、小会議室はマイクなしで30席と狭いです。"},

  {"id":"c328","sec":"総合的に聞く","material":"<div class='mtl-mail'>件名：懇親会の ご案内\n\n日時：10月10日（金）18時〜\n会費：4,000円\n※出欠は 10月<span class='mtl-hl'>3日</span>までに 返信を</div>","setup":"会社で、女の人が 案内メールを 見せながら 男の人に 話して います。","turns":[{"w":"女","t":"懇親会の 出欠、メールでは 3日までですが、幹事さんが、準備の 都合で 一日 早めたいそうです。"},{"w":"男","t":"じゃあ、2日までに 返信すれば いいんだね。"}],"q":"出欠は、いつまでに 返信しますか。","cs":["10月2日","10月3日","10月10日","10月5日"],"a":0,"ex":"メールは3日ですが、会話で「一日早めて2日まで」に変更されました。10日は懇親会当日です。資料と会話の違いに注意します。"},

  {"id":"c329","sec":"総合的に聞く","material":"<table class='mtl-t'><tr><th>係</th><th>担当</th></tr><tr><td class='l'>受付</td><td>田中・佐藤</td></tr><tr><td class='l'>会場</td><td>鈴木</td></tr><tr><td class='l'>記録</td><td>山本</td></tr></table>","setup":"会社で、男の人が 係の 表を 見ながら、女の人に 頼んで います。","turns":[{"w":"男","t":"当日、受付が 二人だと 少し 心配でね。山本さんは 記録だけど、開始前の 30分だけ、受付を 手伝って もらえないかな。"},{"w":"女","t":"分かりました。山本さんに、開始前は 受付を お願いします。"}],"q":"山本さんは、開始前の 30分、何を しますか。","cs":["受付を 手伝う","記録を とる","会場の 準備を する","何も しない"],"a":0,"ex":"山本さんは記録係ですが、「開始前の30分だけ受付を手伝って」と頼まれ、女の人も承知しています。時間限定の変更に注意します。"},

  {"id":"c330","sec":"総合的に聞く","material":"<div class='mtl-mail'>【 電話メモ 】\n課長 へ\n\nC社 山口様 より お電話。\n「明日の 打ち合わせ、資料が そろい次第、こちらから 送る。届いたら、目を 通して おいて ほしい」\nとの ことです。</div>","setup":"席に 戻ると、電話メモが ありました。メモを 見て、まず はじめに どう しますか。","turns":[{"w":"男","t":"（メモを 読んで います）"}],"q":"課長は、まず はじめに 何を しますか。","cs":["C社から 資料が 届くのを 待つ","C社に 資料を 送る","山口様に 電話する","打ち合わせを 始める"],"a":0,"ex":"「資料がそろい次第、こちらから送る。届いたら目を通して」から、送るのは相手（C社）。まずは資料が届くのを待ちます。誰が送るのかに注意します。"}

];
